import { useState, useEffect, useRef, useMemo } from "react";
import {
  FaPlus, FaEdit, FaTrash, FaPrint, FaWhatsapp, FaSearch, FaTimes,
  FaCheck, FaSignOutAlt, FaDownload, FaMoneyBillWave, FaMobileAlt,
  FaUniversity, FaTag, FaChartLine, FaFileInvoice, FaUserTie,
  FaCog, FaChevronDown, FaChevronUp
} from "react-icons/fa";

// ── Constants & Helpers ───────────────────────────────────────────────────────
const COMPANY = "Deep Citadel Laundry Services";
const COMPANY_PHONE = "0244639002";
const WA_NUMBER = "23355244639002";
const PROMO_CODES = { "DCL20": 20, "WELCOME10": 10, "VIP30": 30 };
const PAYMENT_METHODS = [
  { key: "cash", label: "Cash", icon: <FaMoneyBillWave /> },
  { key: "momo", label: "MoMo", icon: <FaMobileAlt /> },
  { key: "bank", label: "Bank", icon: <FaUniversity /> },
];
const DEFAULT_SERVICES = [
  { name: "Wash & Fold", pricePerItem: 50 },
  { name: "Dry Cleaning", pricePerItem: 100 },
  { name: "Ironing", pricePerItem: 20 },
  { name: "Express", pricePerItem: 80 },
];
const WEEK_DAYS = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

const fmt = n => `₵${Number(n).toFixed(2)}`;
const uid = () => Date.now() + Math.random().toString(36).slice(2, 6);
const nowStr = () => new Date().toLocaleString("en-GB", { dateStyle: "medium", timeStyle: "short" });

function load(key, fallback) {
  try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : fallback; } catch { return fallback; }
}
function save(key, val) { try { localStorage.setItem(key, JSON.stringify(val)); } catch { } }

// ── Theme Colors ─────────────────────────────────────────────────────────────
const C = {
  blue: "#0077b6", cyan: "#00d4ff", dark: "#0a0f2e", mid: "#0d2b5e",
  green: "#10b981", yellow: "#f59e0b", red: "#ef4444", purple: "#8b5cf6",
  white: "#ffffff", gray: "#f0f4f8", muted: "#64748b", border: "#e2e8f0",
  text: "#1e293b",
};

// ── Main Component ───────────────────────────────────────────────────────────
export default function LaundryPOS() {
  const [orders, setOrders] = useState(() => load("dcl_pos_orders", []));
  const [services, setServices] = useState(() => load("dcl_pos_services", DEFAULT_SERVICES));
  const [activeTab, setActiveTab] = useState("pos"); 
  const [loaded, setLoaded] = useState(false);

  // Form State
  const [orderType, setOrderType] = useState("walkin");
  const [customerName, setCustomerName] = useState("");
  const [customerPhone, setCustomerPhone] = useState("");
  const [pickupDate, setPickupDate] = useState("");
  const [pickupTime, setPickupTime] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("cash");
  const [promoCode, setPromoCode] = useState("");
  const [promoApplied, setPromoApplied] = useState(null);
  const [promoMsg, setPromoMsg] = useState("");
  const [selections, setSelections] = useState({});
  const [editOrderId, setEditOrderId] = useState(null);
  const formRef = useRef(null);

  // Filter State
  const [search, setSearch] = useState("");
  const [filterPaid, setFilterPaid] = useState("all");
  const [deleteTarget, setDeleteTarget] = useState(null);

  useEffect(() => { setTimeout(() => setLoaded(true), 100); }, []);
  useEffect(() => { save("dcl_pos_orders", orders); }, [orders]);
  useEffect(() => { save("dcl_pos_services", services); }, [services]);

  const selectedItems = services.filter(s => selections[s.name] > 0);
  const subtotal = selectedItems.reduce((a, s) => a + (selections[s.name] || 0) * s.pricePerItem, 0);
  const discount = promoApplied ? Math.round(subtotal * (promoApplied / 100)) : 0;
  const total = subtotal - discount;
  const totalClothes = selectedItems.reduce((a, s) => a + (selections[s.name] || 0), 0);

  const resetForm = () => {
    setCustomerName(""); setCustomerPhone(""); setPickupDate(""); setPickupTime("");
    setPaymentMethod("cash"); setPromoCode(""); setPromoApplied(null); setPromoMsg("");
    setSelections({}); setEditOrderId(null); setOrderType("walkin");
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!customerName.trim() || selectedItems.length === 0) return;
    
    const order = {
      id: editOrderId || uid(),
      invoiceNumber: editOrderId ? orders.find(o => o.id === editOrderId).invoiceNumber : "INV-" + Date.now(),
      orderDate: nowStr(),
      orderType, customerName, customerPhone,
      pickupDate: orderType === "pickup" ? pickupDate : null,
      pickupTime: orderType === "pickup" ? pickupTime : null,
      paymentMethod, promoCode: promoApplied ? promoCode : "",
      discount: promoApplied || 0,
      services: selectedItems.map(s => ({ name: s.name, count: selections[s.name], pricePerItem: s.pricePerItem })),
      totalClothes, subtotal, totalPrice: total,
      paid: editOrderId ? orders.find(o => o.id === editOrderId).paid : false,
    };

    setOrders(prev => editOrderId ? prev.map(o => o.id === editOrderId ? order : o) : [order, ...prev]);
    resetForm();
    setActiveTab("invoices");
  };

  const TAB = (key, label, icon) => (
    <button onClick={() => setActiveTab(key)} style={{
      display: "flex", alignItems: "center", gap: 7, padding: "10px 18px", borderRadius: 10, border: "none", fontWeight: 600, fontSize: 13, cursor: "pointer",
      background: activeTab === key ? "linear-gradient(135deg,#0077b6,#00d4ff)" : "transparent",
      color: activeTab === key ? "#fff" : "rgba(255,255,255,0.5)"
    }}>
      {icon}{label}
    </button>
  );

  return (
    <div style={{ minHeight: "100vh", background: "#f0f4f8", opacity: loaded ? 1 : 0, transition: "opacity 0.4s" }}>
      <style>{`
        * { box-sizing: border-box; margin: 0; padding: 0; font-family: 'DM Sans', sans-serif; }
        .pos-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
        @media(max-width: 800px) { .pos-grid { grid-template-columns: 1fr; } }
      `}</style>

      {/* Header */}
      <div style={{ background: `linear-gradient(135deg,${C.dark},${C.mid})`, padding: "16px 20px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap" }}>
        <h1 style={{ color: "#fff", fontSize: 18, letterSpacing: 1 }}>Deep Citadel POS</h1>
        <div style={{ display: "flex", gap: 8 }}>
          {TAB("pos", "New Order", <FaFileInvoice />)}
          {TAB("invoices", "History", <FaSearch />)}
        </div>
      </div>

      <div style={{ maxWidth: 1000, margin: "0 auto", padding: "20px" }}>
        {activeTab === "pos" ? (
          <div className="pos-grid" ref={formRef}>
            {/* Form Left */}
            <div style={{ background: "#fff", padding: 24, borderRadius: 16, border: `1px solid ${C.border}` }}>
              <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: 14 }}>
                <input style={UI.input} placeholder="Customer Name" value={customerName} onChange={e => setCustomerName(e.target.value)} required />
                <input style={UI.input} placeholder="Phone Number" value={customerPhone} onChange={e => setCustomerPhone(e.target.value)} />
                
                <div style={{ display: "flex", gap: 10 }}>
                  <button type="button" onClick={() => setOrderType("walkin")} style={orderType === "walkin" ? UI.btnActive : UI.btn}>Walk-In</button>
                  <button type="button" onClick={() => setOrderType("pickup")} style={orderType === "pickup" ? UI.btnActive : UI.btn}>Pickup</button>
                </div>

                <button type="submit" style={UI.submitBtn}>
                   {editOrderId ? "Update Order" : "Create Order"} — {fmt(total)}
                </button>
              </form>
            </div>

            {/* Services Right */}
            <div style={{ background: "#fff", padding: 24, borderRadius: 16, border: `1px solid ${C.border}` }}>
              {services.map(s => (
                <div key={s.name} style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: `1px solid ${C.gray}` }}>
                  <span>{s.name} ({fmt(s.pricePerItem)})</span>
                  <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <button onClick={() => setSelections(p => ({ ...p, [s.name]: Math.max(0, (p[s.name] || 0) - 1) }))} style={UI.counterBtn}>-</button>
                    <span style={{ fontWeight: 700 }}>{selections[s.name] || 0}</span>
                    <button onClick={() => setSelections(p => ({ ...p, [s.name]: (p[s.name] || 0) + 1 }))} style={UI.counterBtn}>+</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div style={{ background: "#fff", padding: 20, borderRadius: 16, border: `1px solid ${C.border}` }}>
             <h2 style={{ marginBottom: 15 }}>Order History</h2>
             {/* Simple List View */}
             {orders.map(o => (
               <div key={o.id} style={{ padding: 15, borderBottom: `1px solid ${C.gray}`, display: "flex", justifyContent: "space-between" }}>
                  <div>
                    <strong>{o.customerName}</strong>
                    <div style={{ fontSize: 12, color: C.muted }}>{o.invoiceNumber} • {o.orderDate}</div>
                  </div>
                  <div style={{ fontWeight: 700, color: C.blue }}>{fmt(o.totalPrice)}</div>
               </div>
             ))}
          </div>
        )}
      </div>
    </div>
  );
}

const UI = {
  input: { width: "100%", padding: "12px", borderRadius: "10px", border: `1px solid ${C.border}`, outline: "none" },
  btn: { flex: 1, padding: "10px", borderRadius: "10px", border: `1px solid ${C.border}`, background: "#fff", cursor: "pointer" },
  btnActive: { flex: 1, padding: "10px", borderRadius: "10px", border: `1px solid ${C.blue}`, background: "rgba(0,119,182,0.1)", color: C.blue, fontWeight: 600 },
  submitBtn: { padding: "14px", borderRadius: "10px", background: C.blue, color: "#fff", border: "none", fontWeight: 700, cursor: "pointer" },
  counterBtn: { width: 30, height: 30, borderRadius: "5px", border: "none", background: C.gray, cursor: "pointer", fontWeight: "bold" }
};
